// Normalize_Input (robusto para Telegram Trigger / Webhook / edited_message / callback_query)

const root = $json;

// 1) Detectar el "message" real venga donde venga
const msg =
  root.message ||
  root.body?.message ||
  root.edited_message ||
  root.body?.edited_message ||
  root.callback_query?.message ||
  root.body?.callback_query?.message ||
  root.channel_post ||
  root.body?.channel_post ||
  root;

// 2) Chat / usuario
const chat_id = (msg.chat?.id ?? root.chat?.id)?.toString() || '';
const from = msg.from || root.from || root.body?.message?.from || {};
const telegram_user_id = (from.id ?? '')?.toString() || '';
const username =
  from.username ||
  [from.first_name, from.last_name].filter(Boolean).join(' ') ||
  '';

// 3) Texto
const text = (msg.text || msg.caption || '').trim();
const text_upper = text.toUpperCase();
const message_id = (msg.message_id ?? root.message_id ?? '')?.toString() || '';

// ✅ 3.1) Keyword de cierre (LISTO/DONE/READY)
const is_done_keyword = ['LISTO', 'DONE', 'READY'].includes(text_upper);

// 4) Archivos de voz / audio (soporta voice, audio, video_note, document)
const voice_file_id =
  msg.voice?.file_id ||
  msg.audio?.file_id ||
  msg.video_note?.file_id ||
  msg.document?.file_id ||
  null;

const hasVoice = !!voice_file_id;

return [
  {
    chat_id,
    telegram_user_id,
    username,
    text,
    hasVoice,
    voice_file_id,
    message_id,
    is_done_keyword,
  },
];

