(function () {

  const lang = String($node["GS_Get_Lead_Record"]?.json?.lang || 'ES').trim().toUpperCase();
  const windowHours = 24; // ← cambia aquí si quieres 12/48
  const name = String($node["GS_Get_Lead_Record"]?.json?.q1_name || $json.q1_name || '').trim();

  // ✅ Resumen CONTROLADO por idioma (evita mezcla)
  let summary = '';
  if (lang === 'EN') {
    summary = String(
      $node["AI_Translate_ClientSummary"]?.json?.text
      || $node["AI_Translate_ClientSummary"]?.json?.output?.[0]?.content?.[0]?.text
      || $node["GS_Save_AI_Results"]?.json?.client_summary
      || ''
    ).trim();
  } else {
    summary = String(
      $node["GS_Save_AI_Results"]?.json?.client_summary
      || ''
    ).trim();
  }

  // Textos por idioma
  const greeting = (lang === 'EN') ? 'Hi' : 'Hola';
  const closing = (lang === 'EN') ? 'Best regards' : 'Un saludo';

  const headerSubtitle = (lang === 'EN')
    ? 'Automation diagnosis platform'
    : 'Plataforma de diagnóstico y automatización';

  // ✅ Confirmación (mantener)
  const confirmText = (lang === 'EN')
    ? 'We have received your information and voice notes successfully. Thank you for the level of detail shared.'
    : 'Hemos recibido correctamente tu información y tus notas de voz. Gracias por el nivel de detalle compartido.';

  // ✅ Frase elegante sin repetición (aquí está el cambio)
  const processText = (lang === 'EN')
    ? 'We are now consolidating everything to perform a preliminary technical review and better understand your current situation.'
    : 'En este momento estamos consolidando toda la información para realizar una revisión técnica preliminar y comprender con mayor profundidad tu situación actual.';

  const summaryTitle = (lang === 'EN') ? 'Preliminary summary' : 'Resumen preliminar';

  // Ventana 24h
  const windowText = (lang === 'EN')
    ? '<strong>If you would like to add additional information</strong> (another voice note or text), please send it within the next <strong>' + windowHours + ' hours</strong> through this same channel. After that, we will close this intake cycle and proceed with the internal review.'
    : '<strong>Si deseas agregar información adicional</strong> (otra nota de voz o texto), puedes enviarla dentro de las próximas <strong>' + windowHours + ' horas</strong> por este mismo canal. Después de ese período, cerraremos este ciclo de recepción e iniciaremos la revisión interna.';

  const futureText = (lang === 'EN')
    ? 'If new relevant information appears later, it can be incorporated in a subsequent phase.'
    : 'Si más adelante surge nueva información relevante, podrá incorporarse en una fase posterior del proyecto.';

  // Línea de continuidad (opcional, pero pro)
  const followupText = (lang === 'EN')
    ? 'We will keep you informed about the next step in the process.'
    : 'Te mantendremos informado sobre el siguiente paso del proceso.';

  return (

    '<table width="100%" cellpadding="0" cellspacing="0" style="background:#f6f7fb;padding:24px 0;font-family:Arial,Helvetica,sans-serif;">' +
      '<tr><td align="center">' +

        '<table width="680" cellpadding="0" cellspacing="0" style="background:#ffffff;border:1px solid #e5e7eb;border-radius:14px;overflow:hidden;">' +

          // Header
          '<tr>' +
            '<td style="background:#111827;padding:16px 22px;color:#ffffff;">' +
              '<div style="font-size:16px;font-weight:700;">Perfect Solutions</div>' +
              '<div style="font-size:12px;color:#cbd5e1;margin-top:4px;">' + headerSubtitle + '</div>' +
            '</td>' +
          '</tr>' +

          // Body
          '<tr>' +
            '<td style="padding:22px;font-size:14px;color:#111;line-height:1.7;">' +

              '<p style="margin:0 0 14px 0;">' + greeting + ' <strong>' + (name || '—') + '</strong>,</p>' +

              '<p style="margin:0 0 14px 0;">' + confirmText + '</p>' +

              '<p style="margin:0 0 14px 0;">' + processText + '</p>' +

              '<div style="border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fafafa;margin:16px 0;">' +
                '<div style="font-size:12px;font-weight:700;color:#6b7280;text-transform:uppercase;margin-bottom:8px;">' + summaryTitle + '</div>' +
                '<div style="white-space:pre-line;">' + (summary || '—') + '</div>' +
              '</div>' +

              '<div style="border-left:4px solid #111827;padding-left:14px;margin:0 0 14px 0;">' +
                '<p style="margin:0;">' + windowText + '</p>' +
              '</div>' +

              '<p style="margin:0 0 10px 0;color:#4b5563;">' + futureText + '</p>' +
              '<p style="margin:0 0 18px 0;color:#4b5563;">' + followupText + '</p>' +

              '<p style="margin:0;">' + closing + ',<br><strong>Perfect Solutions</strong></p>' +

            '</td>' +
          '</tr>' +

        '</table>' +

      '</td></tr>' +
    '</table>'
  );

})()
}}

