(() => {
  try {
    const raw =
      $node["AI_Extractor_Tecnico_JSON"]?.json?.text ||
      $node["AI_Extractor_Tecnico_JSON"]?.json?.output?.[0]?.content?.[0]?.text ||
      $node["AI_Extractor_Tecnico_JSON"]?.json?.output?.[0]?.content?.[0]?.output_text ||
      '';

    const obj = JSON.parse(String(raw).trim());
    const hall = obj?.hallazgos || [];

    const hasTools =
      String(obj?.lead_snapshot?.herramientas_actuales || '').trim().length > 0 ||
      hall.some(h => String(h?.tipo || '').toLowerCase() === 'herramienta' && String(h?.item || '').toLowerCase() !== 'unknown');

    const hasPains =
      hall.some(h => String(h?.tipo || '').toLowerCase() === 'dolor' && String(h?.item || '').toLowerCase() !== 'unknown');

    const hasProcs =
      hall.some(h => String(h?.tipo || '').toLowerCase() === 'proceso' && String(h?.item || '').toLowerCase() !== 'unknown');

    const hasOpps =
      hall.some(h => String(h?.tipo || '').toLowerCase() === 'oportunidad' && String(h?.item || '').toLowerCase() !== 'unknown');

    const goal = String(obj?.lead_snapshot?.objetivo_principal || '').trim().length > 0;

    if (hasTools && hasPains && hasProcs && hasOpps && goal) return 0.85;
    if ((hasPains && hasProcs && goal) || (hasPains && hasTools && goal)) return 0.65;
    if (goal || hasTools) return 0.45;
    return 0.3;
  } catch (e) {
    return 0;
  }
})()
}}

