(() => {
  try {
    const n = $node["AI_Extractor_Tecnico_JSON"]?.json;
    const raw = n?.text || n?.output?.[0]?.content?.[0]?.text || n?.output?.[0]?.content?.[0]?.output_text || '';
    const obj = JSON.parse(String(raw).trim());

    // 1) Desde hallazgos.tipo = "herramienta"
    const fromHallazgos = (obj?.hallazgos || [])
      .filter(h => String(h?.tipo || '').toLowerCase() === 'herramienta')
      .map(h => h?.item)
      .filter(Boolean);

    // 2) Fallback: lead_snapshot.herramientas_actuales
    const fromLead = String(obj?.lead_snapshot?.herramientas_actuales || '')
      .split(',')
      .map(s => s.trim())
      .filter(Boolean);

    const tools = [...fromHallazgos, ...fromLead];
    return [...new Set(tools)].join(', ');
  } catch (e) {
    return '';
  }
})()
}}

